#include<bits/stdc++.h>
using namespace std;

int main(){
    string a;
    cin>>a;
    for(int i=0;i<a.size();i++){
        switch(a[i]){
            case 'A':
                cout<<'T';
                break;
            case 'G':
                cout<<'C';
                break;
            case 'T':
                cout<<'A';
                break;
            case 'C':
                cout<<'G';
                break;
        }
    }
    return 0;
}
